{
  "compilerOptions": {
    "experimentalDecorators": true,
    "emitDecoratorMetadata": true
  }
}

// Sadə sinif dekoratoru
function logClass(constructor: Function) {
  console.log(`Created class: ${constructor.name}`);
}

@logClass
class Person {
  constructor(public name: string) {}
  greet(): string {
    return `Hello, ${this.name}!`;
  }
}

const person = new Person('Alice'); // Created class: Person
console.log(person.greet()); // Hello, Alice!

// Dekorator fabriki
function addPrefix(prefix: string) {
  return function (constructor: Function) {
    console.log(`${prefix}: ${constructor.name}`);
  };
}

@addPrefix('Info')
class Person {
  constructor(public name: string) {}
  greet(): string {
    return `Hello, ${this.name}!`;
  }
}

const person = new Person('Alice'); // Info: Person
console.log(person.greet()); // Hello, Alice!

// TypeScript sinif dekoratoru
function sealed(constructor: Function) {
  Object.seal(constructor);
  Object.seal(constructor.prototype);
}

@sealed
class Person {
  constructor(public name: string) {}
  greet(): string {
    return `Hello, ${this.name}!`;
  }
}

const person = new Person('Alice');
console.log(person.greet()); // Hello, Alice!

// Tip təhlükəsizliyi ilə sinif dekoratoru
function restrictClass(constructor: Function) {
  console.log(`Restricted class: ${constructor.name}`);
}

@restrictClass
class Person {
  constructor(public name: string) {}
  greet(): string {
    return `Hello, ${this.name}!`;
  }
}

const person = new Person('Alice'); // Restricted class: Person
console.log(person.greet()); // Hello, Alice!
// const invalid = new Person(123); // Xəta: Argument of type 'number' is not assignable to 'string'

// Səhvə yol açan sinif dekoratoru
function freezeClass(constructor: Function) {
  Object.freeze(constructor);
  Object.freeze(constructor.prototype);
}

@freezeClass
class Person {
  constructor(public name: string) {}
  greet(): string {
    return `Hello, ${this.name}!`;
  }
}

const person = new Person('Alice');
console.log(person.greet()); // Hello, Alice!
// person.greet = () => 'Modified'; // Xəta: Cannot assign to read-only property

// Real layihə ssenarisi
function registerClass(constructor: Function) {
  console.log(`Registered class: ${constructor.name} for dependency injection`);
}

@registerClass
class UserService {
  constructor(public name: string) {}
  getUser(): string {
    return `User: ${this.name}`;
  }
}

const service = new UserService('Alice'); // Registered class: UserService for dependency injection
console.log(service.getUser()); // User: Alice

